#!/usr/bin/env bash
# Local experiment runner — generated by run-experiment skill
# Project: {PROJECT}
# Created: {DATE}
# Commit:  {COMMIT}
#
# Run: bash {SCRIPT_NAME}
# Or in tmux: tmux new-session -d -s {JOB_NAME} 'bash {SCRIPT_NAME}'

set -euo pipefail

JOB_NAME="{JOB_NAME}"
LOG_DIR="{LOG_DIR}"
OUTPUT_DIR="{OUTPUT_DIR}"

mkdir -p "$LOG_DIR" "$OUTPUT_DIR"

LOG_FILE="$LOG_DIR/${JOB_NAME}-$(date +%Y%m%d-%H%M%S).log"

echo "=========================================" | tee "$LOG_FILE"
echo "Job:    $JOB_NAME"                         | tee -a "$LOG_FILE"
echo "Start:  $(date)"                           | tee -a "$LOG_FILE"
echo "Commit: {COMMIT}"                          | tee -a "$LOG_FILE"
echo "Log:    $LOG_FILE"                         | tee -a "$LOG_FILE"
echo "=========================================" | tee -a "$LOG_FILE"

# Activate environment (uncomment as needed)
# conda activate {CONDA_ENV}
# source {PROJECT_ROOT}/.venv/bin/activate

cd {PROJECT_ROOT}

# GPU selection (optional — comment out to use all visible GPUs)
# export CUDA_VISIBLE_DEVICES=0

echo "Running: {RUN_COMMAND}" | tee -a "$LOG_FILE"
echo "-----------------------------------------" | tee -a "$LOG_FILE"

{RUN_COMMAND} 2>&1 | tee -a "$LOG_FILE"

EXIT_CODE=${PIPESTATUS[0]}

echo "-----------------------------------------" | tee -a "$LOG_FILE"
echo "End:  $(date)"  | tee -a "$LOG_FILE"
echo "Exit: $EXIT_CODE" | tee -a "$LOG_FILE"
echo "=========================================" | tee -a "$LOG_FILE"

exit $EXIT_CODE
